import io
import os
import json
from typing import Optional, Tuple, Dict, Any

import torch
import torch.nn as nn
import torchvision
from torchvision import transforms
from PIL import Image

from fastapi import FastAPI, UploadFile, File, Response
from fastapi.responses import JSONResponse

APP_HOST = os.getenv("HOST", "0.0.0.0")
APP_PORT = int(os.getenv("PORT", "8000"))

MODEL_PATH = os.getenv("MODEL_PATH", "")
MODEL_NAME = os.getenv("MODEL_NAME", "resnet18")
NUM_CLASSES = int(os.getenv("NUM_CLASSES", "1000"))
CLASS_NAMES_PATH = os.getenv("CLASS_NAMES_PATH", "")
DEVICE = os.getenv("DEVICE", "cuda" if torch.cuda.is_available() else "cpu")

app = FastAPI(title="Image Classification API", version="1.0.0")

_model: Optional[nn.Module] = None
_class_names: Optional[list] = None


def _load_class_names(path: str) -> Optional[list]:
    if not path:
        return None
    with open(path, "r", encoding="utf-8") as f:
        data = json.load(f)
    if isinstance(data, dict):
        keys = sorted(data.keys(), key=lambda x: int(x) if str(x).isdigit() else str(x))
        return [data[k] for k in keys]
    if isinstance(data, list):
        return data
    return None


def _build_model(name: str, num_classes: int) -> nn.Module:
    name = name.lower().strip()
    if name == "resnet18":
        m = torchvision.models.resnet18(weights=None)
        m.fc = nn.Linear(m.fc.in_features, num_classes)
        return m
    if name == "resnet50":
        m = torchvision.models.resnet50(weights=None)
        m.fc = nn.Linear(m.fc.in_features, num_classes)
        return m
    if name == "mobilenet_v2":
        m = torchvision.models.mobilenet_v2(weights=None)
        m.classifier[1] = nn.Linear(m.classifier[1].in_features, num_classes)
        return m
    if name == "efficientnet_b0":
        m = torchvision.models.efficientnet_b0(weights=None)
        m.classifier[1] = nn.Linear(m.classifier[1].in_features, num_classes)
        return m
    raise ValueError(f"Unsupported MODEL_NAME: {name}")


def _load_model() -> nn.Module:
    global _model
    if _model is not None:
        return _model

    m = _build_model(MODEL_NAME, NUM_CLASSES)

    if MODEL_PATH:
        state = torch.load(MODEL_PATH, map_location="cpu")
        if isinstance(state, dict) and "state_dict" in state and isinstance(state["state_dict"], dict):
            state = state["state_dict"]
        if isinstance(state, dict):
            new_state = {}
            for k, v in state.items():
                nk = k
                if nk.startswith("module."):
                    nk = nk[len("module.") :]
                new_state[nk] = v
            m.load_state_dict(new_state, strict=False)

    m.eval()
    m.to(DEVICE)
    _model = m
    return _model


def _get_class_names() -> Optional[list]:
    global _class_names
    if _class_names is None:
        _class_names = _load_class_names(CLASS_NAMES_PATH)
    return _class_names


def _infer(image_bytes: bytes) -> Tuple[int, float]:
    model = _load_model()

    img = Image.open(io.BytesIO(image_bytes))
    x = transforms.ToTensor()(img).unsqueeze(0).to(DEVICE)

    with torch.no_grad():
        logits = model(x)
        probs = torch.softmax(logits, dim=1)
        conf, idx = torch.max(probs, dim=1)
        return int(idx.item()), float(conf.item())


@app.get("/health")
def health() -> Dict[str, Any]:
    return {"status": "ok", "device": DEVICE, "model_name": MODEL_NAME, "num_classes": NUM_CLASSES}


@app.post("/predict")
async def predict(file: UploadFile = File(...)) -> Response:
    data = await file.read()
    idx, conf = _infer(data)

    names = _get_class_names()
    label = names[idx] if names and 0 <= idx < len(names) else str(idx)

    return JSONResponse(
        {
            "predicted_class": label,
            "class_index": idx,
            "confidence": conf,
        }
    )


if __name__ == "__main__":
    import uvicorn

    uvicorn.run(app, host=APP_HOST, port=APP_PORT)